--select * from identitydevelopment.enterprise.dataimportmapping
;with BlackBookInfo (companyname, companyid, customercompanyid)
AS
(
SELECT tbl.col.value('@companyname[1]', 'varchar(max)') as [companyname]
	,tbl.col.value('@companyid[1]', 'INT') as [companyid]
	,tbl.col.value('@customercompanyid[1]', 'int') as [customercompanyid]
    FROM @priorserverxml .nodes('/root/MiscStuff.dbo.BlackBookCompanies') tbl(col)

)
, CompanyBlackBlueSync ( partyid, blackbookid, bluebookid ) 
AS 
	(
	select dim.partyid, dim.sourceid, BBC.customercompanyid from Enterprise.DataImportMapping DIM
		inner join BlackBookInfo  BBC on DIM.SourceId = BBC.companyid
	where DataImportApplicationId = 1
	)

insert into Enterprise.DataImportMapping ( DataImportApplicationId, SourceId, PartyId, DateCreated )
select 2, cbs.bluebookid, cbs.partyid, GETUTCDATE() from CompanyBlackBlueSync cbs left outer join enterprise.dataimportmapping dim
	on dim.partyid = cbs.partyid 
	and dim.DataImportApplicationId = 2
where dim.SourceId is null

go


